    cin.tie(0);
#define endl '\n'
#define f first
#define s second

typedef unsigned long long llu;
typedef unsigned int ui;
typedef long long ll;

int main()
{
    //_
    string entrada, hash;
    getline(cin, entrada);
    cin >> hash;
    int valor;
    cin >> valor;
    if (valor <= 100)
    {
        cout << "EFETUADA\n";
    }
    else
    {
        stringstream aux(entrada);
        string primeira;
        string ultima;
        string leitura;
        aux >> primeira;
        string verifica = string(1, primeira.at(0));

        while (aux >> leitura)
        {
            ultima = leitura;
            verifica.append(string(1, leitura.at(0)));
        }

        if (primeira == ultima && valor < 500)
        {
            cout << "BLOQUEADA\n";
        }
        else if (verifica == hash)
        {
            cout << "EFETUADA\n";
        }
        else
        {
            cout << "BLOQUEADA\n";
        }
    }

    return 0;
}